import tiktoken
from openai import OpenAI

MODEL = 'gpt-4o'
MAX_TOKENS = 128_000
OUTPUT_HEADROOM = 2_000   # reserve for the reply

enc = tiktoken.encoding_for_model(MODEL)

def trim_history(messages: list[dict]) -> list[dict]:
    'Evict oldest non-system messages until we fit within budget.'
    while True:
        total = sum(4 + len(enc.encode(m.get('content', ''))) for m in messages) + 2
        if total <= MAX_TOKENS - OUTPUT_HEADROOM:
            return messages
        # drop the first non-system message
        for i, m in enumerate(messages):
            if m['role'] != 'system':
                messages.pop(i)
                break
        else:
            return messages   # only system message left
